arguments.argument:
if global.gamePaused=false
{
  x+=bulletSpeed
  
  if bStuck=1
  {
    if instance_exists(stuckID)
    {
      x=stuckID.x+xOffset
      y=stuckID.y+yOffset
      explodeTime-=1
      
      if explodeTime<=10
      {
        if image_blend=c_white {image_blend=c_red}
        else {image_blend=c_white}
      }
      if explodeTime=0
      {
        myAtk=instance_create(x,y,oDragShip_Shot2Exp)
        myAtk.atkPower=atkPower
        instance_destroy()
      }
    }
    else
    {
      instance_destroy()
    }
  }
}
